void read_parameters(char* filename, int* tSize, int* sSize, int* maxMove, fp* alpha) {
    FILE* f = fopen(filename, "r");
    if (!f) {
        printf("Error opening parameter file\n");
        exit(1);
    }
    fscanf(f, "%d", tSize);
    fscanf(f, "%d", sSize);
    fscanf(f, "%d", maxMove);
    fscanf(f, "%f", alpha);
    fclose(f);
}

void read_header(char* filename, int* size, int* size_2) {
    FILE* f = fopen(filename, "r");
    if (!f) {
        printf("Error opening header file\n");
        exit(1);
    }
    fscanf(f, "%d", size);
    fscanf(f, "%d", size_2);
    fclose(f);
}

void read_data(char* filename, int size, int* input_a, int* input_b, int size_2, int* input_2a, int* input_2b) {
    FILE* f = fopen(filename, "r");
    if (!f) {
        printf("Error opening data file\n");
        exit(1);
    }
    int i;
    for (i = 0; i < size; i++) {
        fscanf(f, "%d", &input_a[i]);
        fscanf(f, "%d", &input_b[i]);
    }
    for (i = 0; i < size_2; i++) {
        fscanf(f, "%d", &input_2a[i]);
        fscanf(f, "%d", &input_2b[i]);
    }
    fclose(f);
}

void write_data(char* filename, int frameNo, int frames_processed, int endoPoints, int* input_a, int* input_b, int epiPoints, int* input_2a, int* input_2b) {
    FILE* f = fopen(filename, "w");
    if (!f) {
        printf("Error opening output file\n");
        return;
    }
    int i, j;
    for (i = 0; i < frames_processed; i++) {
        for (j = 0; j < endoPoints; j++) {
            fprintf(f, "%d %d ", input_a[j * frameNo + i], input_b[j * frameNo + i]);
        }
        for (j = 0; j < epiPoints; j++) {
            fprintf(f, "%d %d ", input_2a[j * frameNo + i], input_2b[j * frameNo + i]);
        }
        fprintf(f, "\n");
    }
    fclose(f);
}

void kernel_gpu_opencl_impl(
    params_common d_common,
    fp* d_frame,
    int d_frame_no,
    int* d_endoRow,
    int* d_endoCol,
    int* d_tEndoRowLoc,
    int* d_tEndoColLoc,
    int* d_epiRow,
    int* d_epiCol,
    int* d_tEpiRowLoc,
    int* d_tEpiColLoc,
    fp* d_endoT,
    fp* d_epiT,
    fp* d_in2_all,
    fp* d_conv_all,
    fp* d_in2_pad_cumv_all,
    fp* d_in2_pad_cumv_sel_all,
    fp* d_in2_sub_cumh_all,
    fp* d_in2_sub_cumh_sel_all,
    fp* d_in2_sub2_all,
    fp* d_in2_sqr_all,
    fp* d_in2_sqr_sub2_all,
    fp* d_in_sqr_all,
    fp* d_tMask_all,
